import sys

def main():
    N = int(sys.stdin.readline())
    S = sys.stdin.readline().strip()
    stack = []
    for ch in S:
        if ch == '(':
            stack.append(ch)
        elif ch == ')':
            if stack and stack[-1] == '(':
                stack.pop()
            else:
                stack.append(ch)
        else:
            stack.append(ch)
    print(''.join(stack))

if __name__ == "__main__":
    main()
